import{_ as t,o as r,c as s,ak as n}from"./chunks/framework.DwHlt8HN.js";const g=JSON.parse('{"title":"分布式事务常见解决方案总览","description":"","frontmatter":{},"headers":[],"relativePath":"distributed/transaction/solution-overview.md","filePath":"distributed/transaction/solution-overview.md","lastUpdated":1774318215000}'),i={name:"distributed/transaction/solution-overview.md"};function e(l,a,o,d,p,h){return r(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="分布式事务常见解决方案总览" tabindex="-1">分布式事务常见解决方案总览 <a class="header-anchor" href="#分布式事务常见解决方案总览" aria-label="Permalink to “分布式事务常见解决方案总览”">​</a></h1><p>凌晨 3 点，你的报警平台突然炸了——订单服务说库存服务没扣库存，库存服务说订单服务没发请求，财务系统一脸懵逼：「钱扣了，货呢？」</p><p>这不是 bug，这是分布式事务的经典困境：<strong>跨服务的数据一致性</strong>。</p><p>为什么分布式事务是分布式系统最大的难题之一？因为它直接撞上了 <a href="/distributed/theory/cap">CAP 理论</a> 的天花板—— Consistency（一致性）、Availability（可用性）、Partition tolerance（分区容错性），三者只能选其二，而网络分区是必然发生的。</p><p>换句话说：<strong>在分布式系统中，要么接受数据不一致，要么接受系统不可用</strong>。分布式事务的种种方案，本质上都是在这两者之间寻找平衡点。</p><h2 id="从强一致到最终一致-一条艰难的路" tabindex="-1">从强一致到最终一致：一条艰难的路 <a class="header-anchor" href="#从强一致到最终一致-一条艰难的路" aria-label="Permalink to “从强一致到最终一致：一条艰难的路”">​</a></h2><p>分布式事务解决方案可以分为两大阵营：</p><p><strong>强一致性方案</strong>：不惜一切代价保证数据完全一致</p><p><strong>最终一致性方案</strong>：允许短暂的不一致，但保证最终一致</p><table tabindex="0"><thead><tr><th>方案</th><th>一致性级别</th><th>性能</th><th>开发成本</th><th>适用场景</th></tr></thead><tbody><tr><td>2PC/3PC</td><td>强一致</td><td>差</td><td>中</td><td>对数据一致性要求极高的场景</td></tr><tr><td>Seata AT</td><td>强一致</td><td>中</td><td>低</td><td>业务代码无侵入，支持单库多表</td></tr><tr><td>Seata TCC</td><td>最终一致</td><td>高</td><td>高</td><td>高性能，强一致性，业务可改写</td></tr><tr><td>Saga</td><td>最终一致</td><td>高</td><td>中</td><td>长事务，流程编排</td></tr><tr><td>可靠消息</td><td>最终一致</td><td>高</td><td>中</td><td>异步解耦，允许短暂不一致</td></tr><tr><td>最大努力通知</td><td>最终一致</td><td>高</td><td>低</td><td>通知类场景，允许失败重试</td></tr></tbody></table><p>没有银弹，每种方案都是<strong>一致性、成本、性能</strong>的权衡。选错方案，轻则系统卡顿，重则数据错乱。</p><h2 id="强一致性方案-2pc-与-3pc" tabindex="-1">强一致性方案：2PC 与 3PC <a class="header-anchor" href="#强一致性方案-2pc-与-3pc" aria-label="Permalink to “强一致性方案：2PC 与 3PC”">​</a></h2><h3 id="_2pc-two-phase-commit" tabindex="-1">2PC（Two-Phase Commit） <a class="header-anchor" href="#_2pc-two-phase-commit" aria-label="Permalink to “2PC（Two-Phase Commit）”">​</a></h3><p><a href="/distributed/theory/2pc">2PC</a> 是最经典的分布式事务协议，由协调者（Coordinator）和参与者（Participant）组成：</p><p><strong>一阶段（投票阶段）</strong>：</p><ul><li>协调者向所有参与者发送「准备好」请求</li><li>参与者执行事务，但不提交</li><li>参与者返回「同意」或「反对」</li></ul><p><strong>二阶段（提交阶段）</strong>：</p><ul><li>如果所有参与者都返回「同意」，协调者发送「提交」指令</li><li>如果任何一个参与者返回「反对」，协调者发送「回滚」指令</li></ul><p><strong>2PC 的致命缺陷</strong>：</p><ul><li><strong>同步阻塞</strong>：参与者收到「准备好」后，必须阻塞等待，直到收到提交或回滚</li><li><strong>单点故障</strong>：协调者挂了，参与者就死等了</li><li><strong>数据不一致</strong>：协调者发送「提交」后挂了，只有部分参与者收到提交，导致数据不一致</li></ul><h3 id="_3pc-three-phase-commit" tabindex="-1">3PC（Three-Phase Commit） <a class="header-anchor" href="#_3pc-three-phase-commit" aria-label="Permalink to “3PC（Three-Phase Commit）”">​</a></h3><p><a href="/distributed/theory/3pc">3PC</a> 是 2PC 的改良版，把提交分成三个阶段：</p><ul><li><strong>CanCommit</strong>：协调者问参与者「你们能提交吗」</li><li><strong>PreCommit</strong>：协调者告诉参与者「准备提交」，超时自动中断</li><li><strong>DoCommit</strong>：真正提交</li></ul><p>3PC 解决了同步阻塞和单点故障的部分问题（超时机制），但<strong>数据不一致问题依然存在</strong>。</p><p>强一致性方案的共同问题：<strong>性能太差</strong>。全局锁、多次网络通信、参与者必须等待——这套机制在互联网高并发场景下几乎不可用。</p><h2 id="最终一致性方案-百花齐放" tabindex="-1">最终一致性方案：百花齐放 <a class="header-anchor" href="#最终一致性方案-百花齐放" aria-label="Permalink to “最终一致性方案：百花齐放”">​</a></h2><p>强一致性方案性能太差，所以最终一致性方案应运而生。</p><p>核心思想：<strong>放弃实时一致，接受短暂不一致，用补偿机制保证最终一致。</strong></p><h3 id="tcc-try-confirm-cancel" tabindex="-1">TCC（Try-Confirm-Cancel） <a class="header-anchor" href="#tcc-try-confirm-cancel" aria-label="Permalink to “TCC（Try-Confirm-Cancel）”">​</a></h3><p><a href="/distributed/transaction/seata-tcc">Seata TCC 模式</a> 把每个分布式事务分成三步：</p><ol><li><strong>Try</strong>：预留资源，但不提交</li><li><strong>Confirm</strong>：确认执行，使用预留的资源</li><li><strong>Cancel</strong>：取消执行，释放预留的资源</li></ol><p>关键点：<strong>Try/Confirm/Cancel 都需要业务方自己实现</strong>。TCC 是业务层面的补偿，需要在代码里写好预留、确认、取消的逻辑。</p><h3 id="saga" tabindex="-1">Saga <a class="header-anchor" href="#saga" aria-label="Permalink to “Saga”">​</a></h3><p><a href="/distributed/transaction/seata-saga">Seata Saga 模式</a> 适合长事务编排。把一个大事务拆成多个小事务，每个小事务都有对应的补偿操作。正向执行，出错就反向补偿。</p><p><strong>TCC vs Saga</strong>：</p><ul><li>TCC 是「先锁定再执行」，资源在 Try 阶段就被预留了</li><li>Saga 是「直接执行，出事再补偿」，不锁定资源</li></ul><h3 id="可靠消息" tabindex="-1">可靠消息 <a class="header-anchor" href="#可靠消息" aria-label="Permalink to “可靠消息”">​</a></h3><p><a href="/distributed/transaction/reliable-message">可靠消息最终一致性方案</a> 的核心是<strong>消息队列</strong>。本地事务执行成功后，消息一定被投递到下游。</p><p>两种实现方式：</p><ul><li><strong>本地消息表</strong>：本地事务 + 消息表，用定时任务轮询投递</li><li><strong>RocketMQ 事务消息</strong>：半消息（Half Message）机制，反查本地事务状态</li></ul><h3 id="最大努力通知" tabindex="-1">最大努力通知 <a class="header-anchor" href="#最大努力通知" aria-label="Permalink to “最大努力通知”">​</a></h3><p><a href="/distributed/transaction/best-effort-notify">最大努力通知方案</a> 是「可靠消息」的镜像——可靠消息保证发送方，<strong>最大努力通知保证接收方</strong>。</p><p>典型场景：支付回调、订单状态同步。核心机制是<strong>重复通知 + 指数退避 + 衰减通知次数</strong>。</p><h2 id="选型决策树-怎么快速选择" tabindex="-1">选型决策树：怎么快速选择？ <a class="header-anchor" href="#选型决策树-怎么快速选择" aria-label="Permalink to “选型决策树：怎么快速选择？”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>需要强一致性？</span></span>
<span class="line"><span>├── 是 → 业务代码能改吗？</span></span>
<span class="line"><span>│   ├── 能 → TCC（高性能）或 AT（零侵入）</span></span>
<span class="line"><span>│   └── 不能 → AT 模式（如果有框架支持）</span></span>
<span class="line"><span>└── 否 → 是异步解耦还是长事务？</span></span>
<span class="line"><span>    ├── 异步解耦 → 可靠消息（MQ 事务消息）</span></span>
<span class="line"><span>    └── 长事务 → Saga 编排</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>更详细的选型分析：<a href="/distributed/transaction/mode-compare">AT vs TCC vs SAGA 对比与选型</a></p><h2 id="面试追问方向" tabindex="-1">面试追问方向 <a class="header-anchor" href="#面试追问方向" aria-label="Permalink to “面试追问方向”">​</a></h2><ol><li><p><strong>CAP 理论在分布式事务中怎么体现？</strong></p><ul><li>强一致性方案选择了 C+P，意味着可能牺牲可用性</li><li>最终一致性方案选择了 A+P，在网络分区时保证可用，允许短暂不一致</li></ul></li><li><p><strong>2PC 的数据不一致问题怎么解决？</strong></p><ul><li>加协调者选举 Zab/Raft 协议</li><li>或者干脆不用 2PC，用最终一致性方案</li></ul></li><li><p><strong>如果让你设计一个分布式事务框架，核心模块有哪些？</strong></p><ul><li>事务协调器：管理全局事务状态</li><li>分支事务注册：让参与者加入全局事务</li><li>补偿/回滚机制：处理失败情况</li><li>隔离性保证：全局锁或资源预留</li></ul></li><li><p><strong>本地消息表和 RocketMQ 事务消息的区别？</strong></p><ul><li>本地消息表：业务自己实现，需要轮询任务</li><li>RocketMQ 事务消息：MQ 原生支持，反查机制更可靠</li></ul></li></ol><h2 id="没有银弹" tabindex="-1">没有银弹 <a class="header-anchor" href="#没有银弹" aria-label="Permalink to “没有银弹”">​</a></h2><p>分布式事务的难点不在于找到「完美方案」，而在于<strong>理解每种方案的权衡</strong>，根据业务场景做出合理选择。</p><p>是追求强一致还是最终一致？业务代码能改吗？性能要求有多高？能接受多长时间的窗口期？</p><p>这些问题没有标准答案，只有最适合当前业务的答案。</p><p>下次遇到分布式事务问题，别急着找框架，先问自己：这笔交易能承受多长时间的「不一致」？</p>`,53)])])}const b=t(i,[["render",e]]);export{g as __pageData,b as default};
